public class FinalMethod {
    static class Base {
        final String tag() { return "Base"; }
        String describe() { return "I am " + tag(); }
    }
    static class Sub extends Base {
        // cannot override tag() — it's final
        String describe() { return "Sub says: " + tag(); }
    }
    public static void main(String[] args) {
        Base b = new Sub();
        System.out.println(b.describe());
        System.out.println(b.tag());
    }
}
